#include<bits/stdc++.h>
using namespace std;

int main() {
	int n;
	cin>>n;
	for(int i=1; i<=n; i++) {
		for(int j=1; j<=n; j++) {
			if((i==n/2+1)&&(j==n/2+1)) {
				cout<<"x";
			}
			else if((j==1||j==n||(j==n/2+1)&&i!=1&&i!=n)) {
				cout<<"|";
			} else if((i==1||i==n||i==n/2+1)) {
				cout<<"-";
			}

			else {
				cout<<"x";
			}
		}
		cout<<"\n";
	}
	return 0;
}
